import type {IKitsPhoneInput} from "@lmb-it/kitsconcerto-types";
import {KitsContainer, KitsInputText, Icon} from "../../../_compat";
import {useImperativeHandle, useMemo} from "react";
import {useSeparator} from "../../../factory";
import {usePhoneInput} from "./usePhoneInput";
import {SvgUri} from "react-native-svg";
import {View} from "react-native";
import {useComponentDefaults} from "@lmb-it/kitsconcerto/hooks";


const KitsPhoneComponent =
    (
        {
            ref,
            isWithCountryCode,
            label,
            value,
            placeholder,
            onChange,
            invalid,
            disabled,
            required,
            errors,
            hideError,
            id,
            defaultCountry,
            inputSize,
            isFloatedLabel,
            leftAddon,
            rightAddon,
            includedCountries,
            excludedCountries,
            outputFormat='string',
            ...props
        }: IKitsPhoneInput
    ) => {
        const { mergedProps: _mergedProps, themeStyle, elementStyles } = useComponentDefaults('PhoneInput', props as any, 'Input');
        const {nativeProps} = useSeparator<any>(props);

        const {
            displayValue,
            e164Value,
            objectValue,
            countryFlagUrl,
            countryISO,
            handleChange,
        } = usePhoneInput({
            value,
            onChange,
            outputFormat,
            isWithCountryCode,
            defaultCountry,
            includedCountries,
            excludedCountries,
        });

        useImperativeHandle(ref, () => ({
            value: outputFormat === 'object' ? (objectValue ?? e164Value) : e164Value,
            setValue: (v: any) => handleChange(typeof v === "string" ? v : ""),
        }));

        const flagAddon = useMemo(() => {
            if (!isWithCountryCode) return leftAddon;

            if (countryFlagUrl) {
                return (
                    <View style={{width: 20, height: 20, overflow: 'hidden', borderRadius: 2}}>
                        <SvgUri
                            uri={countryFlagUrl}
                            width={20}
                            height={20}
                        />
                    </View>
                );
            }

            return <Icon name="phone" size={'2xs'}/>;
        }, [isWithCountryCode, countryFlagUrl, countryISO, leftAddon]);

        return (
            <KitsContainer
                id={id}
                inputSize={inputSize}
                isFloatedLabel={isFloatedLabel}
                errors={errors}
                required={required}
                hideError={hideError}
                label={label}
                elementStyles={elementStyles}
            >
                <KitsInputText
                    id={`${id}-phone`}
                    keyboardNavId={id}
                    value={displayValue}
                    rightAddon={rightAddon}
                    leftAddon={flagAddon}
                    onChange={(e: any) => handleChange(e.target.value)}
                    invalid={invalid}
                    disabled={disabled}
                    placeholder={placeholder ?? (isWithCountryCode ? "+1 (555) 123-4567" : "")}
                    localProps={Object.keys(themeStyle).length ? { style: { width: '100%', ...(themeStyle as any) } } : undefined}
                />
            </KitsContainer>
        );
    }


export default KitsPhoneComponent;
